// Parse Telegram message
const update = items[0].json;
let messageType = 'unknown';
let chatId = null;
let text = '';
let callbackData = '';
let userId = null;

if (update.message) {
  messageType = 'message';
  chatId = update.message.chat.id;
  text = update.message.text || '';
  userId = update.message.from.id;
} else if (update.callback_query) {
  messageType = 'callback';
  chatId = update.callback_query.message.chat.id;
  callbackData = update.callback_query.data;
  userId = update.callback_query.from.id;
}

return [{
  json: {
    messageType,
    chatId,
    text,
    callbackData,
    userId,
    original: update
  }
}];

// Route commands
const text = items[0].json.text;
const chatId = items[0].json.chatId;

let command = '';
let response = '';

if (text.startsWith('/help')) {
  command = 'help';
  response = '🤖 Tech LEAD Commands:\n\n/status - Current work status\n/pause - Pause automation\n/resume - Resume automation\n/projects - List active projects\n/help - Show this help\n\nOr just ask me anything about the project!';
} else if (text.startsWith('/status')) {
  command = 'status';
  response = '📊 Tech LEAD is operational\n\nOrchestrator: Active\nMonitoring: Active\nGitHub Integration: Connected\nNocoDB: Connected';
} else if (text.startsWith('/pause')) {
  command = 'pause';
  response = '⏸️ Tech LEAD paused. Use /resume to continue.';
} else if (text.startsWith('/resume')) {
  command = 'resume';
  response = '▶️ Tech LEAD resumed. Automation active.';
} else if (text.startsWith('/projects')) {
  command = 'projects';
  response = '📁 Active Projects:\n\n• techLEAD\n  https://github.com/Lucasmind/techLEAD\n  Status: active';
} else {
  command = 'unknown';
  response = '❓ Unknown command. Use /help to see available commands.';
}

return [{
  json: {
    command,
    response,
    chatId
  }
}];
